import type { CareerQuestion } from "./rrt-questions";

export const otaQuestionsBatch14: CareerQuestion[] = [
  { id: "ota-2303", stem: "An OTA is evaluating a client with ideomotor apraxia. What task would reveal this deficit?", options: ["Verbal naming of objects", "Asking the client to pantomime using a toothbrush or comb — they cannot perform learned motor acts on command despite intact motor and sensory function", "Visual field testing", "Memory recall tasks"], correctIndex: 1, rationale: "Ideomotor apraxia: inability to perform motor acts on command or imitation despite intact motor function. Can perform actions automatically but not on request. Test by asking to pantomime tool use without the actual object present.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2304", stem: "A client with a recent kidney transplant is in OT. What infection prevention measure is critical?", options: ["No special measures", "Strict hand hygiene, avoid live plants/flowers in the room, wear a mask in crowded areas, and monitor for signs of infection due to immunosuppressive medications", "Only avoid raw meat", "Standard precautions only"], correctIndex: 1, rationale: "Post-transplant immunosuppression: strict hand hygiene, avoid live plants/soil (fungal risk), mask in crowded areas, avoid sick contacts, report fever immediately, and monitor wound sites for infection signs.", difficulty: 2, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2305", stem: "An OTA is treating a child with autism who lines up toys repetitively. What does this behavior represent?", options: ["Creative play", "Restricted and repetitive behavior — a core diagnostic feature of autism spectrum disorder reflecting need for sameness and order", "Advanced organizational skills", "Typical toddler play"], correctIndex: 1, rationale: "Lining up objects is a restricted/repetitive behavior (RRB) in ASD — reflects insistence on sameness, need for order, and restricted interests. OT approach: gradually expand play repertoire, honor the behavior while introducing variations.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2306", stem: "A client with Guillain-Barré syndrome is on a ventilator. What early OT intervention is appropriate?", options: ["Aggressive strengthening", "Positioning, PROM to prevent contractures, sensory stimulation, communication support, and psychosocial support", "No OT until weaned from ventilator", "Ambulation training"], correctIndex: 1, rationale: "GBS on ventilator: positioning (prevent contractures, skin breakdown), gentle PROM, sensory stimulation, communication support (eye blinks, communication board), psychosocial support, and family education. Avoid overwork.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2307", stem: "An OTA is treating a client with a PIP joint fracture-dislocation. After dorsal blocking splint removal at 3 weeks, what is the treatment focus?", options: ["Aggressive passive extension", "Active ROM exercises for PIP flexion and extension within limits, buddy taping for stability, and gentle edema management", "No exercise for 6 more weeks", "Maximum resistance exercises"], correctIndex: 1, rationale: "PIP fracture-dislocation post-dorsal blocking splint: AROM exercises, buddy taping for stability, gentle edema management, extension splinting between exercises if needed, and progressive strengthening at 6-8 weeks.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2308", stem: "A client with Parkinson's disease has festinating gait during functional mobility. What cueing strategy helps?", options: ["Walk faster", "External rhythmic auditory cues (metronome, music) or visual floor markers to regulate step length and cadence", "No cues help", "Only medication adjustment"], correctIndex: 1, rationale: "Parkinson's festination: external cues bypass basal ganglia dysfunction. Rhythmic auditory (metronome, music beat), visual (floor tape lines to step over), and verbal cues regulate gait pattern and prevent festination.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2309", stem: "An OTA is fabricating a thumb CMC stabilization splint. What landmark must the splint clear?", options: ["Wrist crease", "Thenar crease — the splint must not obstruct MCP flexion or oppose thumb opposition by blocking the thenar eminence", "DIP joint", "Proximal forearm"], correctIndex: 1, rationale: "Thumb CMC splint must clear the thenar crease and MCP joint to allow thumb IP/MCP flexion and opposition. Extend distally to just proximal to thumb MCP crease. Extend proximally to mid-forearm for forearm-based design.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Splinting" },
  { id: "ota-2310", stem: "A client with chronic pain attends an OT pain management program. What outcome measure tracks functional improvement?", options: ["Only VAS pain scale", "Canadian Occupational Performance Measure (COPM) — measures self-perceived performance and satisfaction in meaningful occupations", "Only medication use", "Only grip strength"], correctIndex: 1, rationale: "Chronic pain outcome measurement: COPM (occupation-based performance/satisfaction), Pain Self-Efficacy Questionnaire, Oswestry Disability Index, DASH, and functional capacity evaluations. Focus on function, not just pain intensity.", difficulty: 2, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2311", stem: "An OTA is treating a client with compartment syndrome of the forearm after a fracture. What signs would indicate an emergency?", options: ["Mild discomfort", "The 5 P's: Pain out of proportion, Paresthesia, Paralysis, Pallor, and Pulselessness — pain with passive finger extension is the earliest sign", "Normal swelling", "Mild bruising"], correctIndex: 1, rationale: "Compartment syndrome 5 P's: Pain (out of proportion, with passive stretch), Paresthesia, Paralysis, Pallor, Pulselessness. Pain with passive finger extension is earliest/most reliable sign. Surgical emergency — immediate fasciotomy needed.", difficulty: 3, category: "Patient Safety", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2312", stem: "A client with a left CVA has Broca's aphasia. How should the OTA modify communication?", options: ["Speak louder", "Use simple sentences, yes/no questions, visual cues, allow extra response time, and avoid condescending tone — the client's comprehension is better than expression", "Avoid all communication", "Only write instructions"], correctIndex: 1, rationale: "Broca's aphasia: non-fluent, telegraphic speech but relatively preserved comprehension. OTA: use simple sentences, yes/no questions, visual supports, allow extra time for response, don't finish sentences, and maintain adult-level interaction.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2313", stem: "An OTA is providing intervention for a client with chronic kidney disease who has peripheral neuropathy. What precaution is essential during hand therapy?", options: ["Apply maximum heat", "Test sensation before applying thermal modalities and use caution with sharp instruments due to decreased protective sensation", "No precautions needed", "Use aggressive massage"], correctIndex: 1, rationale: "CKD peripheral neuropathy: decreased protective sensation. Test sensation before thermal modalities, protect hands from burns/cuts, inspect skin regularly, use caution with sharp tools, and educate about injury prevention.", difficulty: 2, category: "Patient Safety", topic: "Hand Therapy" },
  { id: "ota-2314", stem: "A client with a complete C8 SCI has which functional capability?", options: ["No hand function", "Intact grip strength with some intrinsic weakness — can perform most ADLs independently including fine motor tasks with mild difficulty", "Ventilator-dependent", "No upper extremity function"], correctIndex: 1, rationale: "C8 SCI: extrinsic hand muscles intact (finger flexion/extension), some intrinsic weakness (lumbricals, interossei). Can perform most ADLs independently. Fine motor tasks mildly impaired. Independent in wheelchair and transfers.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2315", stem: "An OTA is adapting a bathing routine for a client with bilateral upper extremity weakness from muscular dystrophy. Which equipment is MOST helpful?", options: ["Standard washcloth", "Long-handled bath sponge, shower chair, handheld shower, pump-style dispensers, and toweling mitt for drying", "No adaptations available", "Only sponge baths"], correctIndex: 1, rationale: "Bilateral UE weakness bathing: shower chair, handheld shower (reduces reaching), long-handled sponge, pump dispensers (eliminates gripping bottles), terry cloth bath mitts, suction-cup holders, and adequate grab bar support.", difficulty: 1, category: "Assistive Devices", topic: "ADL Training" },
  { id: "ota-2316", stem: "A client is being evaluated for return to driving after a stroke. What visual skill is essential for safe driving?", options: ["Color vision only", "Adequate visual acuity, intact visual fields, visual scanning speed, depth perception, and contrast sensitivity", "Only distance vision", "Night vision only"], correctIndex: 1, rationale: "Driving visual requirements: visual acuity (state-specific minimums), visual fields (minimum 120° horizontal), visual scanning (rapid eye movements), depth perception, contrast sensitivity, and glare recovery. Vision screening is first step in driver evaluation.", difficulty: 2, category: "Rehabilitation Planning", topic: "ADL Training" },
  { id: "ota-2317", stem: "An OTA is providing intervention for a child with fetal alcohol spectrum disorder (FASD). Which cognitive deficit is MOST common?", options: ["Superior memory", "Executive function deficits including poor planning, impulsivity, difficulty with abstract thinking, and impaired cause-and-effect reasoning", "Only motor deficits", "Only social deficits"], correctIndex: 1, rationale: "FASD cognitive profile: executive function deficits (planning, organization, impulse control), difficulty with abstract thinking, poor cause-effect reasoning, memory problems, slow processing speed, and math difficulties despite relatively preserved verbal skills.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2318", stem: "A client with a recent stroke demonstrates synergy patterns. The flexion synergy in the upper extremity includes:", options: ["Shoulder extension, elbow extension", "Shoulder abduction/external rotation, elbow flexion, forearm supination, wrist/finger flexion — a mass movement pattern seen in early motor recovery", "Isolated finger extension", "Normal movement patterns"], correctIndex: 1, rationale: "UE flexion synergy: scapular retraction/elevation, shoulder abduction/ER, elbow flexion, forearm supination, wrist/finger flexion. This mass pattern occurs in Brunnstrom Stage 2-3 and must be graded toward isolated movement.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2319", stem: "An OTA is providing home modification recommendations for a client who uses a wheelchair. What is the recommended ramp slope ratio?", options: ["1:6 (very steep)", "1:12 ratio — one inch of rise for every twelve inches of length, per ADA accessibility guidelines", "1:3 ratio", "1:20 ratio is the only option"], correctIndex: 1, rationale: "ADA ramp slope: maximum 1:12 (1 inch rise per 12 inches of run). For every 30 inches of rise, a 5-foot landing is required. Preferred slope is 1:16 to 1:20 for easier propulsion. Handrails required on both sides.", difficulty: 1, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2320", stem: "A client with attention deficit disorder has difficulty completing a morning routine. Which OT strategy is MOST helpful?", options: ["Longer task lists", "Break routine into sequential steps, use visual checklists, minimize distractions, establish consistent routine, and use timers for each step", "Verbal reminders only", "Complete tasks for the client"], correctIndex: 1, rationale: "ADD morning routine strategies: task analysis (break into steps), visual checklist, consistent sequence, timer for each step, minimize distractions, organize supplies night before, and positive reinforcement for completion.", difficulty: 1, category: "Clinical Case Scenarios", topic: "Cognitive Rehab" },
  { id: "ota-2321", stem: "An OTA is treating a client with a humeral head replacement (hemiarthroplasty). What is the MOST important precaution?", options: ["No precautions", "Follow surgeon-specific ROM limits, avoid combined shoulder extension-internal rotation-adduction to prevent dislocation", "Full activity immediately", "Only avoid overhead activities"], correctIndex: 1, rationale: "Shoulder hemiarthroplasty precautions: surgeon-specific ROM limits, avoid combined extension-IR-adduction (dislocation risk), PROM before AROM, sling per protocol, and avoid lifting >5 lbs for 6-12 weeks.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2322", stem: "A client with osteogenesis imperfecta (brittle bone disease) is referred to OT. What precaution is paramount?", options: ["Aggressive joint mobilization", "Handle with extreme care, avoid unnecessary force during all activities, use lightweight adaptive equipment, and focus on safe functional activities within bone tolerance", "Standard handling techniques", "Only strengthening exercises"], correctIndex: 1, rationale: "Osteogenesis imperfecta: extreme care with handling (fractures from minimal force), lightweight equipment, safe positioning, gentle ROM, functional activities within tolerance, and fall prevention. Avoid resistive activities.", difficulty: 2, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2323", stem: "An OTA is treating a client with a healed Achilles tendon repair. What is the OT focus?", options: ["Only ankle exercises", "Modified ADL training including footwear management (unable to wear flat shoes initially), shower/bath transfers with restricted weight-bearing, and stair negotiation", "No OT indicated", "Only upper body exercises"], correctIndex: 1, rationale: "Achilles repair OT: modified ADL training (transfers with weight-bearing restrictions), footwear management (heel lift/walking boot), shower safety, stair negotiation, and home modification recommendations during recovery.", difficulty: 2, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2324", stem: "A client with a traumatic brain injury exhibits perseveration. What does this mean?", options: ["Inability to recall events", "Repetitive continuation of a response or activity when it is no longer appropriate — the client cannot shift from one task or idea to another", "Inability to initiate tasks", "Loss of visual perception"], correctIndex: 1, rationale: "Perseveration: inappropriate repetition of a behavior, response, or idea after it is no longer relevant. Client gets 'stuck' and cannot shift. Intervention: redirect, provide clear transitions, and break tasks into distinct segments.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2325", stem: "An OTA is providing ergonomic education for a client returning to office work after carpal tunnel release. What workstation setup is essential?", options: ["Keyboard higher than elbows", "Keyboard at elbow height, wrists in neutral position, ergonomic mouse, monitor at eye level, and regular micro-breaks every 20-30 minutes", "No modifications needed", "Standing desk only"], correctIndex: 1, rationale: "Post-CTS ergonomics: keyboard at elbow height, wrists neutral (no deviation), ergonomic mouse, monitor at eye level, forearm support, micro-breaks every 20-30 minutes, stretching program, and gradual return to full typing.", difficulty: 1, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2326", stem: "A client with a vestibular schwannoma (acoustic neuroma) removal has facial nerve involvement. Which functional concern should the OTA address?", options: ["Only hearing", "Facial weakness affecting eye closure (corneal protection), eating (food pocketing), drinking, and facial expression for social communication", "Only balance", "Only headache"], correctIndex: 1, rationale: "Facial nerve (CN VII) involvement: facial weakness causes inability to close eye (corneal protection needed), difficulty eating (food pocketing in cheek), drinking (lip seal), and social impact (facial expression loss). OT addresses functional impact.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2327", stem: "An OTA is treating a client with rheumatoid arthritis who has MCP joint subluxation. Which activity modification reduces joint stress?", options: ["Carry items with fingers", "Use the palms of both hands to carry objects, use built-up handles, and avoid lateral pinch forces that increase ulnar deviation at the MCPs", "Grip tightly with one hand", "No modifications needed"], correctIndex: 1, rationale: "RA MCP subluxation activity modification: use palms/forearms for carrying (not fingers), built-up handles, avoid lateral pinch forces, use lever handles, lightweight utensils, and avoid positions that increase ulnar deviation.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Rehabilitation Principles" },
  { id: "ota-2328", stem: "A client with a developmental disability is being transitioned from a sheltered workshop to supported employment. What does the OTA assess?", options: ["Only IQ score", "Work skills, social skills, community mobility, self-care independence, job match, and need for accommodations/job coaching support", "Only physical capacity", "Only interests"], correctIndex: 1, rationale: "Transition to supported employment: assess work skills (task completion, following directions), social skills, community mobility, self-care, interests, strengths, job match, accommodation needs, and job coaching requirements.", difficulty: 2, category: "Rehabilitation Planning", topic: "ADL Training" },
  { id: "ota-2329", stem: "An OTA is assessing a client's occupational performance using the Assessment of Motor and Process Skills (AMPS). What does this evaluation measure?", options: ["Only motor skills", "Quality of motor and process (cognitive) skill performance during familiar ADL tasks in a natural environment", "Only process skills", "Only self-care independence"], correctIndex: 1, rationale: "AMPS: observational assessment measuring quality of motor skills (stabilizes, reaches, manipulates, coordinates) and process skills (attends, organizes, adapts, sequences) during 2-3 familiar ADL tasks. Evaluates both how well and how efficiently tasks are performed.", difficulty: 3, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2330", stem: "A client with a cervical SCI at C5 wants to feed independently. What adaptive setup is required?", options: ["Standard utensils", "Mobile arm support, universal cuff with built-up utensils, plate guard, non-slip mat, and adapted cup with extended straw", "Only modified utensils", "Client cannot feed at C5"], correctIndex: 1, rationale: "C5 SCI feeding: mobile arm support (compensates for lack of antigravity function), universal cuff (compensates for no grasp), built-up utensils, plate guard, non-slip mat, adapted cup with long straw. Modified independence achievable.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Assistive Devices" },
  { id: "ota-2331", stem: "An OTA is working with a client who has a conversion disorder presenting as non-organic blindness. What approach is appropriate?", options: ["Confront the client", "Focus on functional goals, provide supportive environment, gradually increase functional expectations through meaningful activities, and coordinate with psychology", "Prove the client can see", "Discharge from services"], correctIndex: 1, rationale: "Conversion disorder: avoid confrontation, focus on function (ADLs, occupational goals), supportive/non-judgmental approach, graded activity, stress management, and coordinate with psychiatry/psychology for underlying psychological factors.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2332", stem: "A client with spina bifida at L4 level has which functional mobility expectation?", options: ["Full wheelchair dependence", "Community ambulation with ankle-foot orthoses (AFOs) and forearm crutches — intact hip flexors and knee extensors allow functional walking", "No assistive devices needed", "Only household ambulation"], correctIndex: 1, rationale: "L4 spina bifida: hip flexors (L2), hip adductors (L3), and knee extensors (L3-L4) intact. Community ambulation with AFOs and crutches expected. May use wheelchair for long distances/efficiency. OT addresses UE function for device use.", difficulty: 3, category: "Pediatric Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2333", stem: "An OTA is providing splinting for a client with a mallet finger. What error would cause treatment failure?", options: ["Wearing the splint too much", "Allowing the DIP to drop into flexion when changing the splint — even one episode of DIP flexion restarts the healing timeline", "Performing PIP exercises", "Keeping the splint clean"], correctIndex: 1, rationale: "Mallet finger splinting critical error: if DIP drops into flexion during splint changes, the healing timeline restarts. Keep DIP supported on a table edge during splint changes. Continuous extension for 6-8 weeks without interruption.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Splinting" },
  { id: "ota-2334", stem: "A client with schizophrenia has disorganized thinking. Which OT intervention helps organize daily routines?", options: ["Complex verbal instructions", "Visual schedules, step-by-step task checklists, consistent daily routine, environmental organization, and simple one-step verbal cues", "Group discussion about organizing", "Only medication management"], correctIndex: 1, rationale: "Disorganized thinking interventions: visual schedules, written checklists, consistent routine, environmental organization, one-step cues, minimize choices, structured activities, and external organizational systems to compensate for internal disorganization.", difficulty: 1, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2335", stem: "An OTA is treating a client with a PIP joint contracture at 45° flexion. Which splinting approach is evidence-based?", options: ["Forceful manipulation", "Serial static or static progressive splinting providing low-load prolonged stretch to gradually increase PIP extension over time", "Dynamic flexion splinting", "No splinting after 45°"], correctIndex: 1, rationale: "PIP flexion contracture: serial static (progressively remold as ROM improves) or static progressive (adjustable outrigger increases extension force). Low-load prolonged stress (LLPS) principle — 6-8 hours/day for tissue remodeling.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Splinting" },
  { id: "ota-2336", stem: "A client with severe obesity is having difficulty with perineal hygiene. Which adaptive equipment is MOST helpful?", options: ["Only longer arms", "Extended-reach toilet aid with angled handle to assist with hygiene, bidet attachment, and adapted clothing for easier toileting", "No equipment exists", "Only wet wipes"], correctIndex: 1, rationale: "Bariatric toileting aids: extended-reach toilet aid (angled handle), bidet or bidet attachment (reduces need for reaching), raised bariatric toilet seat, grab bars rated for weight, and adapted clothing (elastic waistbands, Velcro closures).", difficulty: 2, category: "Assistive Devices", topic: "ADL Training" },
  { id: "ota-2337", stem: "An OTA is evaluating a client's visual scanning ability after a right CVA. What assessment activity is used?", options: ["Reading comprehension test", "Letter cancellation or line bisection task — asking the client to cross out all targets on a page to assess for left-sided neglect", "Hearing test", "Manual muscle testing"], correctIndex: 1, rationale: "Visual scanning assessment: letter/symbol cancellation (cross out all A's), line bisection (mark center of horizontal lines), clock drawing, reading (missing left side of text), and star cancellation. Tests for unilateral neglect.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2338", stem: "A client with post-traumatic stress disorder avoids all activities that remind them of the trauma. Which OT approach is appropriate?", options: ["Force exposure immediately", "Graded occupation-based exposure within a trauma-informed care framework, building coping skills before exposure, and processing through meaningful activities", "Avoid all triggers permanently", "Only talk therapy"], correctIndex: 1, rationale: "PTSD OT approach: trauma-informed care framework, establish safety first, build coping skills (grounding, breathing), then graded exposure through meaningful occupations. Avoid retraumatization. Coordinate with mental health team.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2339", stem: "An OTA is treating a client with a distal interphalangeal joint arthrodesis (fusion). What is the functional implication?", options: ["No functional impact", "Loss of DIP flexion but increased stability and pain relief for pinch — the client needs training in adapted pinch patterns for small object manipulation", "Loss of all finger function", "Loss of grip entirely"], correctIndex: 1, rationale: "DIP arthrodesis: eliminates DIP motion but provides stable, pain-free fingertip for pinch. Functional impact: difficulty picking up thin/flat objects. Compensate with pad-to-pad or lateral pinch. Most ADL function preserved.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2340", stem: "A client with progressive supranuclear palsy has frequent falls backward. What safety strategy is essential?", options: ["Walk faster", "Environmental modifications, gait aids, vision strategies for vertical gaze palsy, and supervised mobility with fall prevention measures", "Only ankle braces", "No interventions help"], correctIndex: 1, rationale: "Progressive supranuclear palsy: backward falls (postural instability + vertical gaze palsy), environmental modification (remove obstacles behind), weighted walker, vision strategies, supervised mobility, and hip protectors for fall prevention.", difficulty: 4, category: "Neurological Rehabilitation", topic: "Geriatric OT" },
  { id: "ota-2341", stem: "An OTA is providing intervention for a child with developmental dyspraxia. Which approach is MOST effective?", options: ["Repetitive drill practice", "Task-specific training using the CO-OP approach — teaching the child cognitive strategies (Goal-Plan-Do-Check) for motor problem-solving", "Only sensory integration", "Wait for maturation"], correctIndex: 1, rationale: "Developmental dyspraxia: CO-OP approach (cognitive strategy use for motor learning), task-specific practice, metacognitive strategies, environmental modification, and graded activity challenges. Evidence supports top-down approaches over bottom-up.", difficulty: 3, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2342", stem: "A client on Coumadin/warfarin therapy has an INR of 4.5. What should the OTA be concerned about?", options: ["INR is normal", "Elevated INR increases bleeding risk — avoid activities that may cause cuts, bruising, or falls; notify the medical team of the elevated value", "INR is too low", "No concern for OT"], correctIndex: 1, rationale: "INR 4.5 (therapeutic range usually 2.0-3.0): significantly elevated bleeding risk. Avoid activities with fall/cut/bruise risk, no aggressive PROM or deep tissue work, and notify medical team. OT activity should be modified for safety.", difficulty: 2, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2343", stem: "An OTA is teaching a client with C6 SCI to perform upper body dressing. What technique is used for donning a T-shirt?", options: ["Standard overhead method", "Position shirt on lap, place both arms in sleeves using wrist extension and mouth assistance, then duck head through neck opening and use wrist extension to pull down", "Always use button-down shirts", "Requires full assistance"], correctIndex: 1, rationale: "C6 SCI overhead dressing: position shirt on lap face-down, insert both arms, use wrist extension/tenodesis to pull sleeves up, duck head through neck opening, use elbow flexion and wrist extension to pull shirt down. Modified independence achievable.", difficulty: 3, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2344", stem: "A client with reflex sympathetic dystrophy (CRPS Type I) of the hand has severe edema, pain, and vasomotor changes. What is the treatment priority?", options: ["Aggressive ROM", "Pain management, edema reduction, stress loading program, and gentle active motion within pain tolerance", "Complete immobilization", "Only hot packs"], correctIndex: 1, rationale: "CRPS Type I treatment priority: pain management first, then edema reduction (elevation, compression, retrograde massage), stress loading (scrubbing, carrying), gentle AROM (pain-free), desensitization, and mirror therapy.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2345", stem: "An OTA is evaluating a child's visual perception. What is the difference between visual perception and visual-motor integration?", options: ["They are identical", "Visual perception is interpreting visual information without a motor response; visual-motor integration requires coordinating visual input with a motor output like drawing or writing", "Visual-motor is only about eyes", "Visual perception requires motor response"], correctIndex: 1, rationale: "Visual perception: interpreting visual input (discrimination, spatial relationships, figure-ground) without motor component. Visual-motor integration: coordinating visual perception with motor output (copying shapes, handwriting, cutting). Different assessments for each.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2346", stem: "A client with a traumatic brain injury has poor self-awareness and overestimates their abilities. What approach promotes awareness?", options: ["Verbal confrontation", "Structured experiential feedback — have the client predict performance on a task, perform it, then compare prediction to actual performance with objective data", "Accept the client's self-assessment", "Only written education"], correctIndex: 1, rationale: "TBI impaired self-awareness: experiential feedback (predict, perform, compare), video review of performance, structured group feedback, self-rating scales compared to clinician ratings, and gradually increasing task complexity to reveal limitations.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2347", stem: "An OTA is treating a client with de Quervain's who has failed conservative treatment. After surgical release, what is the OT focus?", options: ["Immobilization for 8 weeks", "Scar management, gentle AROM of wrist and thumb, edema control, and gradual return to functional activities over 4-6 weeks", "Full activity immediately", "No OT post-surgery"], correctIndex: 1, rationale: "Post-de Quervain's release: scar management (massage, silicone), gentle AROM (wrist, thumb), edema control, splinting for comfort if needed, gradual return to activities, and strengthening at 4-6 weeks per surgeon protocol.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2348", stem: "A client with a spinal cord injury is performing independent pressure relief. How often should weight shifts be performed?", options: ["Once per hour", "Every 15-30 minutes for at least 15-30 seconds to allow adequate tissue reperfusion and prevent pressure injury formation", "Only when uncomfortable", "Three times per day"], correctIndex: 1, rationale: "SCI pressure relief: weight shifts every 15-30 minutes for 15-30 seconds minimum. Methods: wheelchair push-up, lean forward, lean side-to-side, or tilt wheelchair. Power wheelchair users: tilt/recline function.", difficulty: 1, category: "Patient Education", topic: "Neurological Rehab" },
  { id: "ota-2349", stem: "An OTA is working with a child who has Down syndrome and low muscle tone. Which activity promotes postural control?", options: ["Lying flat on the floor", "Weight-bearing activities such as prone on elbows, hands-and-knees position, and ball activities that challenge balance while providing proprioceptive input", "Only passive exercises", "Vigorous aerobic activity"], correctIndex: 1, rationale: "Down syndrome postural control: weight-bearing (prone on elbows, quadruped, standing), ball activities (sitting on therapy ball), vestibular input, proprioceptive activities, and functional play in various positions to build stability.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2350", stem: "A client with a long arm cast for a humeral shaft fracture needs adaptive strategies for one-handed activities. What does the OTA teach?", options: ["Wait until cast removal", "One-handed techniques for dressing, hygiene, meal preparation, and use of adaptive equipment such as non-slip mat, electric can opener, and rocker knife", "Only non-dominant hand exercises", "No OT during casting"], correctIndex: 1, rationale: "Long arm cast one-handed adaptations: one-handed dressing techniques, non-slip mat, rocker knife, adapted cutting board, pump dispensers, electric can opener, Velcro closures, and temporary dominance retraining if dominant arm is casted.", difficulty: 1, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2351", stem: "An OTA is treating a client with Wilson's disease. What neurological symptom is characteristic?", options: ["Unilateral weakness", "Dystonia, tremor, and dysarthria from copper accumulation in the basal ganglia affecting motor control and coordination", "Only cognitive decline", "Only visual disturbances"], correctIndex: 1, rationale: "Wilson's disease neurological symptoms: tremor (wing-beating), dystonia, dysarthria, drooling, dysphagia, gait abnormalities, and personality/psychiatric changes. Caused by copper deposition in basal ganglia and brain. OT addresses functional impact.", difficulty: 4, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2352", stem: "A client with a recent diagnosis of type 1 diabetes needs OT education. What self-management skills does the OTA address?", options: ["Only insulin injection technique", "Blood glucose monitoring technique, recognition of hypoglycemia/hyperglycemia symptoms, foot care inspection routine, and meal planning strategies", "Only dietary education", "No OT role in diabetes"], correctIndex: 1, rationale: "Diabetes self-management OT: blood glucose monitoring technique, hypoglycemia/hyperglycemia recognition, foot inspection routine, meal planning, medication management, activity pacing with blood sugar monitoring, and problem-solving for sick days.", difficulty: 1, category: "Patient Education", topic: "Rehabilitation Principles" },
  { id: "ota-2353", stem: "An OTA is treating a client with a flexor digitorum profundus avulsion (Jersey finger). After surgical repair, what is the rehabilitation approach?", options: ["Aggressive active flexion", "Dorsal blocking splint with controlled passive flexion and early active extension within the splint to promote tendon healing and prevent adhesions", "No rehabilitation needed", "Immediate full ROM"], correctIndex: 1, rationale: "FDP avulsion (Jersey finger) post-repair: dorsal blocking splint (wrist 30° flexion, MCPs 70° flexion), controlled passive flexion within splint, active extension to splint limits, and progression per surgeon protocol. Similar to Zone I flexor tendon repair protocol.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2354", stem: "A client with a personality disorder frequently tests boundaries with the OTA. What approach is therapeutic?", options: ["Change boundaries frequently", "Maintain consistent boundaries, use clear communication, avoid power struggles, document interactions, and coordinate with the treatment team", "Become friends with the client", "Ignore boundary violations"], correctIndex: 1, rationale: "Personality disorder boundary management: consistent limits, clear communication, avoid power struggles, maintain therapeutic distance, document behaviors, team coordination for consistent approach, and avoid splitting.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2355", stem: "An OTA is assessing a client's functional mobility in the bathroom. Which transfer requires the MOST advanced balance?", options: ["Wheelchair to bed", "Tub transfer without equipment — stepping over the tub wall requires dynamic standing balance, weight shifting, and single-leg stance", "Wheelchair to commode", "Seated transfer with sliding board"], correctIndex: 1, rationale: "Tub transfer without equipment: requires dynamic balance, single-leg stance (stepping over tub wall), weight shifting, and coordination. Most challenging bathroom transfer. Equipment (tub bench, grab bars) reduces difficulty.", difficulty: 2, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2356", stem: "A client with a new pacemaker has which activity restrictions?", options: ["No restrictions", "Avoid raising the arm on the pacemaker side above shoulder height for 4-6 weeks, avoid heavy lifting, and stay away from strong electromagnetic fields", "Avoid all arm movement", "Only avoid swimming"], correctIndex: 1, rationale: "Pacemaker restrictions: limit ipsilateral arm elevation above 90° for 4-6 weeks (lead displacement risk), avoid heavy lifting >10 lbs, avoid strong EMI sources (MRI, large magnets, welding equipment), and modify ADLs accordingly.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2357", stem: "An OTA is treating a child with sensory processing disorder who frequently mouths non-food objects. Which oral sensory strategy is appropriate?", options: ["Punish the behavior", "Provide appropriate oral sensory input through chewy tubes, vibrating toothbrush, crunchy/chewy foods, and whistles to redirect the oral seeking behavior", "Ignore the behavior", "Tape the child's mouth"], correctIndex: 1, rationale: "Oral sensory seeking: provide appropriate alternatives — chewy tubes, vibrating oral tools, crunchy/chewy foods during snacks, whistles, blowing activities, and oral-motor exercises. Redirect rather than punish the sensory-seeking behavior.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "Sensory Processing" },
  { id: "ota-2358", stem: "A client with a distal radius fracture and ORIF is 4 weeks post-surgery. The surgeon clears for active ROM. What exercises does the OTA initiate?", options: ["Resistive grip exercises", "Active wrist flexion/extension, radial/ulnar deviation, forearm pronation/supination, and gentle composite finger exercises within pain tolerance", "Only passive ROM by therapist", "Full weight-bearing through the wrist"], correctIndex: 1, rationale: "Distal radius ORIF at 4 weeks: initiate AROM — wrist flexion/extension, radial/ulnar deviation, forearm rotation, and finger exercises. Avoid resistive exercise until 6-8 weeks. Monitor for hardware irritation and edema.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2359", stem: "An OTA is providing intervention for a client with hoarding disorder who feels overwhelmed by decluttering. What strategy helps?", options: ["Throw everything away at once", "Start with a small defined area, use a sorting system (keep/donate/discard), make decisions together, and celebrate progress to build self-efficacy", "Only discuss the hoarding", "Avoid the home entirely"], correctIndex: 1, rationale: "Hoarding intervention: start small (one drawer, one shelf), sorting system, collaborative decision-making, pace the process (avoid overwhelming), cognitive techniques for attachment to objects, and celebrate incremental progress.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2360", stem: "A client with severe burns over 40% TBSA is in the rehabilitation phase. What is the expected duration of scar maturation?", options: ["2-4 weeks", "12-18 months on average, sometimes up to 2 years — pressure garments and scar management continue throughout this period", "1 month", "1 week"], correctIndex: 1, rationale: "Burn scar maturation: 12-18 months (up to 2 years). Pressure garments worn 23 hours/day throughout. Scar management (massage, silicone, moisturizing) continues until scar is mature (flat, soft, pale). OT addresses function throughout.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Rehabilitation Principles" },
  { id: "ota-2361", stem: "An OTA is treating a client with multiple system atrophy. Which combination of symptoms is characteristic?", options: ["Only tremor", "Parkinsonism combined with autonomic dysfunction (orthostatic hypotension, bladder/bowel dysfunction) and/or cerebellar ataxia", "Only cognitive decline", "Only mood disturbance"], correctIndex: 1, rationale: "Multiple system atrophy: combination of parkinsonism (rigidity, bradykinesia, poor levodopa response), autonomic dysfunction (orthostatic hypotension, urinary), and/or cerebellar ataxia. Progressive neurodegeneration. OT addresses safety and function.", difficulty: 4, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2362", stem: "A client with chronic lymphedema of the arm requires long-term management. What is the OTA's role in a complete decongestive therapy program?", options: ["Only bandaging", "Skin care education, self-manual lymph drainage technique training, compression garment management, exercise programming, and activity modification", "Only exercise prescription", "No OT role"], correctIndex: 1, rationale: "OTA role in lymphedema CDT: skin care education, self-MLD technique training, compression garment donning/management, decongestive exercises, activity modification, adaptive equipment, and self-management education for lifelong care.", difficulty: 3, category: "Patient Education", topic: "Rehabilitation Principles" },
  { id: "ota-2363", stem: "An OTA is treating a child with cerebral palsy who demonstrates the ATNR reflex at age 4. What is the clinical significance?", options: ["Normal finding", "Persistent primitive reflex indicating neurological immaturity — ATNR should integrate by 4-6 months and its persistence interferes with midline activities and bilateral coordination", "Advanced development", "No significance"], correctIndex: 1, rationale: "Persistent ATNR at age 4: abnormal — should integrate by 4-6 months. Interferes with midline hand use, bilateral coordination, visual tracking, feeding, and rolling. Treatment: weight-bearing activities, midline activities, and reflex integration techniques.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2364", stem: "A client with a replaced aortic valve is on long-term anticoagulation. What activity precaution should the OTA address?", options: ["No precautions", "Avoid contact activities and situations with high fall/injury risk due to increased bleeding tendency from anticoagulant therapy", "Only avoid water activities", "Increase physical activity intensity"], correctIndex: 1, rationale: "Mechanical valve anticoagulation: lifelong warfarin with target INR. OT precautions: fall prevention, avoid contact activities/sharp tools without protection, monitor for bleeding signs, and coordinate with medical team regarding activity levels.", difficulty: 2, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2365", stem: "An OTA is providing sensory modulation strategies for a client in a psychiatric inpatient unit who is becoming escalated. What intervention is appropriate?", options: ["Physical restraint", "Offer a weighted blanket, dim lighting, calming music, a quiet space, and deep breathing techniques to de-escalate through sensory regulation", "Ignore the escalation", "Only PRN medication"], correctIndex: 1, rationale: "Sensory modulation for de-escalation: weighted blanket (deep pressure), dim lighting, calming music/nature sounds, quiet room, aromatherapy (lavender), fidgets, cold water, and guided deep breathing. Evidence-based alternative to seclusion/restraint.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2366", stem: "A client with a pisotriquetral joint injury has pain on the ulnar side of the wrist. What splinting approach does the OTA use?", options: ["Full arm splint", "Wrist splint with ulnar-sided support that limits wrist extension and ulnar deviation to reduce stress on the pisotriquetral joint", "Thumb spica only", "No splinting indicated"], correctIndex: 1, rationale: "Pisotriquetral joint injury: wrist splint with ulnar support, limit extension and ulnar deviation, activity modification (avoid ulnar-sided loading), padding for protection, and gradual return to activities as pain resolves.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2367", stem: "An OTA is treating a client with right homonymous hemianopsia. What side of the visual field is affected?", options: ["Left visual field of left eye only", "The right visual field of BOTH eyes — the client cannot see anything to the right from either eye", "Only peripheral vision", "Central vision only"], correctIndex: 1, rationale: "Right homonymous hemianopsia: loss of right visual field in BOTH eyes. Caused by left posterior cerebral artery stroke/left occipital lobe damage. Compensatory strategies: head turning right, right-anchored scanning, and environmental adaptation.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2368", stem: "A client is being evaluated for adaptive driving equipment. The client has left below-knee amputation. What modification is needed?", options: ["Left-foot accelerator", "No modification needed — automatic transmission vehicles use the right foot for both gas and brake, so a left BKA does not affect standard driving", "Hand controls", "Steering wheel knob"], correctIndex: 1, rationale: "Left BKA and driving: no vehicle modification typically needed for automatic transmission (right foot operates gas and brake). May need modifications only if bilateral amputations or additional impairments. Reassess with prosthesis if applicable.", difficulty: 2, category: "Rehabilitation Planning", topic: "ADL Training" },
  { id: "ota-2369", stem: "An OTA is providing a life skills group for adolescents in a mental health setting. Which topic is MOST important for community transition?", options: ["Academic tutoring", "Money management, grocery shopping, meal preparation, public transportation use, and basic household management for independent living skills", "Only social media literacy", "Only physical fitness"], correctIndex: 1, rationale: "Adolescent mental health life skills: money management, grocery shopping, meal prep, transportation, household management, personal hygiene, time management, and community resource access. Essential for successful transition to independent living.", difficulty: 1, category: "Rehabilitation Planning", topic: "ADL Training" },
  { id: "ota-2370", stem: "A client with a proximal phalanx fracture is being treated with buddy taping during functional activities. What is the purpose of buddy taping?", options: ["Immobilize the finger completely", "Provide lateral stability to the healing fracture while allowing functional finger flexion and extension for ADL participation", "Increase grip strength", "Prevent infection"], correctIndex: 1, rationale: "Buddy taping: tape injured finger to adjacent finger for lateral stability during functional activities. Allows flexion/extension for function while protecting against lateral stress. Use padding between fingers to prevent maceration.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2371", stem: "An OTA is treating a client with dysphagia and is co-treating with a speech-language pathologist. What is the OTA's specific role?", options: ["Determine the diet texture", "Address positioning, self-feeding skills, adaptive equipment for feeding, environmental setup, and UE function to support safe independent eating", "Only observe", "Prescribe swallowing exercises"], correctIndex: 1, rationale: "OTA role in dysphagia co-treatment: positioning (90° upright), self-feeding skills, adaptive feeding equipment, environmental setup (reduce distractions), UE function for feeding, and follow SLP's diet/liquid recommendations.", difficulty: 1, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2372", stem: "A client with a lateral collateral ligament injury of the elbow has varus instability. What does the OTA need to avoid during therapy?", options: ["Elbow flexion", "Varus stress to the elbow — activities that push the forearm inward relative to the upper arm, which would stress the healing lateral ligament", "All arm activities", "Supination"], correctIndex: 1, rationale: "LCL elbow injury: avoid varus stress (forearm pushed medially), avoid carrying heavy objects with arm extended, hinged brace for protection, and graded ROM/strengthening per surgeon protocol. OTA modifies activities to avoid varus loading.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2373", stem: "An OTA is providing intervention for a client with chronic pain using acceptance and commitment therapy (ACT) principles. What is the goal?", options: ["Eliminate all pain", "Help the client accept the presence of pain while committing to value-based actions and meaningful occupational engagement despite pain", "Only distraction techniques", "Only medication management"], correctIndex: 1, rationale: "ACT for chronic pain: accept pain experience (not try to eliminate), cognitive defusion (thoughts are just thoughts), present-moment awareness, values clarification, committed action toward values-based goals, and engagement in meaningful occupations despite pain.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2374", stem: "A client with a replanted finger (digit replantation) has strict protocols. What is the critical precaution in the early postoperative phase?", options: ["Active ROM immediately", "Avoid any tension on the repaired structures, maintain elevation, protect vascular anastomosis from cold/nicotine, and follow strict motion protocols", "Full weight-bearing through the finger", "No precautions needed"], correctIndex: 1, rationale: "Digit replantation precautions: protect vascular repair (avoid cold, nicotine, caffeine), elevation, monitor perfusion (color, temperature, capillary refill), strict surgeon motion protocol, bulky dressing protection, and avoid any tension on repairs.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2375", stem: "An OTA is providing caregiver training for a client with advanced Parkinson's disease. Which technique addresses freezing of gait during ADLs?", options: ["Push the client", "External cues such as counting 1-2-3 before stepping, marching in place, using a laser pointer to create a visual target on the floor, or stepping over an imaginary line", "Wait indefinitely", "Only medication adjustment"], correctIndex: 1, rationale: "Parkinson's freezing strategies: rhythmic counting (1-2-3, step), marching in place, visual cues (laser pointer, floor tape), weight shifting, stepping over imaginary/real line, and auditory metronome. Teach caregivers to cue rather than push.", difficulty: 2, category: "Patient Education", topic: "Neurological Rehab" },
  { id: "ota-2376", stem: "A client with a wrist arthroscopy for TFCC debridement is 2 weeks post-surgery. What is the treatment focus?", options: ["Full weight-bearing through wrist", "Edema management, gentle AROM within pain-free limits, scar care for portal sites, and progressive return to wrist function", "No treatment for 8 weeks", "Aggressive strengthening"], correctIndex: 1, rationale: "Post-TFCC arthroscopy at 2 weeks: edema management, gentle AROM (wrist flexion/extension, pronation/supination within pain limits), portal site scar care, and progressive return to activities. Strengthening at 4-6 weeks per surgeon.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2377", stem: "An OTA is treating a client with severe hand osteoarthritis who cannot open water bottles. Which adaptive strategy is simplest?", options: ["Only use a caregiver", "Use a rubber grip pad or non-slip rubber sheet to increase friction and reduce the force needed to open twist-off bottle caps", "Only use cups", "Surgery for grip strength"], correctIndex: 1, rationale: "Bottle opening adaptations: rubber grip pad/sheet (increases friction, reduces force), electric jar opener, universal opener tools, bottle cap openers mounted under cabinet, and pre-opened bottles stored in accessible containers.", difficulty: 1, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2378", stem: "A client with a spinal cord injury at T12 has which functional mobility expectation?", options: ["Wheelchair-dependent", "Community ambulation with bilateral KAFOs and crutches/walker — intact hip flexors (L2), but needs bracing for knee/ankle stability", "No mobility aids needed", "Bed-bound"], correctIndex: 1, rationale: "T12 SCI: hip flexors partially innervated, but quadriceps and below weak/absent. Functional ambulation with bilateral KAFOs and forearm crutches. Wheelchair for community distance and energy conservation. Independent in wheelchair mobility.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2379", stem: "An OTA is providing intervention for a child who has difficulty with bilateral shoelace tying. At what age should this skill typically be mastered?", options: ["3 years", "6-7 years — shoe tying requires advanced bilateral coordination, fine motor control, motor planning, and visual-motor integration", "2 years", "10 years"], correctIndex: 1, rationale: "Shoe tying developmental milestone: 6-7 years. Requires bilateral hand coordination, fine motor control, sequencing, motor planning, and visual-motor integration. Until mastered, use elastic laces, Velcro shoes, or slip-ons.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2380", stem: "A client with chronic regional pain syndrome has allodynia. What does this symptom mean?", options: ["Numbness", "Pain from a stimulus that would not normally cause pain, such as light touch or air movement on the affected area", "Excessive sweating", "Muscle weakness"], correctIndex: 1, rationale: "Allodynia: pain from normally non-painful stimuli (light touch, clothing contact, air movement). Common in CRPS. Treatment: desensitization program (graded exposure to textures and touch), mirror therapy, and graded motor imagery.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2381", stem: "An OTA is treating a client with frontotemporal dementia (FTD). How does this differ from Alzheimer's disease?", options: ["No differences", "FTD presents earlier (40-65 years) with personality changes, behavioral disinhibition, and language deficits before memory loss, unlike Alzheimer's which begins with memory impairment", "FTD only affects motor function", "FTD is curable"], correctIndex: 1, rationale: "FTD vs Alzheimer's: earlier onset (40-65), personality/behavioral changes precede memory loss, social disinhibition, apathy, compulsive behaviors, and language variants (progressive non-fluent aphasia, semantic dementia). Memory relatively preserved early.", difficulty: 4, category: "Neurological Rehabilitation", topic: "Geriatric OT" },
  { id: "ota-2382", stem: "A client with an acute exacerbation of COPD is hospitalized. What activity level is appropriate for OT intervention?", options: ["Aggressive exercise program", "Bedside ADL training with monitoring of oxygen saturation, heart rate, and dyspnea level, pacing activities within medical tolerance", "No OT during acute phase", "Running in hallways"], correctIndex: 1, rationale: "Acute COPD exacerbation OT: bedside ADLs within tolerance, monitor O2 sat (maintain >88-90%), HR, dyspnea (Borg scale), pursed-lip breathing during activities, energy conservation education, and gradual activity progression per medical status.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2383", stem: "An OTA is performing a sensory evaluation of the hand. Which test assesses two-point discrimination?", options: ["Monofilament testing", "Disk-Criminator or Boley gauge — measures the minimum distance at which two simultaneous points of contact can be distinguished from one", "Pinprick testing only", "Temperature testing only"], correctIndex: 1, rationale: "Two-point discrimination: measures innervation density. Static 2PD (Disk-Criminator): normal <6mm fingertips. Moving 2PD: more sensitive, normal <3mm. Tests functional sensation needed for fine motor tasks. Apply longitudinally on fingertip.", difficulty: 2, category: "Clinical Scenarios", topic: "Hand Therapy" },
  { id: "ota-2384", stem: "A client with a prosthetic above-elbow arm is learning terminal device (TD) operation. What body motion controls elbow flexion?", options: ["Shoulder internal rotation", "Shoulder flexion and scapular abduction activate the cable system to lock/unlock and flex the prosthetic elbow", "Wrist extension", "Trunk rotation"], correctIndex: 1, rationale: "Above-elbow body-powered prosthesis: shoulder flexion/scapular abduction generates cable excursion. Dual-control cable: elbow lock/unlock and TD operation. Humeral flexion to 90° locks/unlocks elbow. Additional flexion operates TD.", difficulty: 4, category: "Clinical Case Scenarios", topic: "Assistive Devices" },
  { id: "ota-2385", stem: "An OTA is treating a client with post-concussion syndrome 3 months after a mild TBI. Which symptoms are characteristic?", options: ["Only headache", "Persistent headache, dizziness, fatigue, difficulty concentrating, memory problems, irritability, and light/noise sensitivity affecting daily occupational performance", "Complete recovery by now", "Only physical symptoms"], correctIndex: 1, rationale: "Post-concussion syndrome (>3 months): headache, dizziness, fatigue, cognitive complaints (concentration, memory), irritability, sleep disturbance, light/noise sensitivity, anxiety/depression. OT addresses functional impact on daily occupations.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2386", stem: "A client with chronic venous insufficiency has lower extremity edema. What positioning does the OTA recommend during seated activities?", options: ["Legs dependent below heart", "Elevate legs above heart level when possible, avoid prolonged sitting with legs dependent, and wear compression stockings during activities", "Legs crossed", "No positioning matters"], correctIndex: 1, rationale: "Chronic venous insufficiency: elevate legs above heart when possible, avoid prolonged dependent position, compression stockings during activities, ankle pumps during sitting, and regular position changes. OT addresses functional impact.", difficulty: 1, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2387", stem: "An OTA is assessing a child's play skills. At what age does cooperative play typically emerge?", options: ["12 months", "4-5 years — children engage in organized group play with shared goals, assigned roles, and cooperative interaction", "6 months", "2 years"], correctIndex: 1, rationale: "Play development: solitary (0-2 years), onlooker (2), parallel (2-3), associative (3-4), cooperative (4-5+). Cooperative play involves organized activity with shared goals, role assignment, and group cooperation.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2388", stem: "A client with a severe TBI demonstrates decorticate posturing. What level of consciousness does this indicate?", options: ["Alert and oriented", "Severe brain injury with upper extremity flexion (arms flexed, wrists flexed, fingers clenched) and lower extremity extension — indicates damage above the red nucleus", "Mild confusion", "Normal motor response"], correctIndex: 1, rationale: "Decorticate posturing: UE flexion (shoulder adduction, elbow/wrist/finger flexion), LE extension. Indicates damage above the red nucleus (cortical/subcortical). More favorable prognosis than decerebrate. GCS motor score of 3.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2389", stem: "An OTA is treating a client with complex regional pain syndrome who demonstrates kinesiophobia. What does this mean?", options: ["Fear of water", "Fear of movement or re-injury that leads to avoidance of physical activity and functional decline", "Fear of heights", "Fear of social situations"], correctIndex: 1, rationale: "Kinesiophobia: excessive fear of movement/re-injury leading to activity avoidance, deconditioning, and functional decline. Common in chronic pain/CRPS. Treatment: education, graded exposure to movement, cognitive restructuring, and functional activity engagement.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2390", stem: "A client with amyotrophic lateral sclerosis can no longer write. What alternative communication method should the OTA introduce?", options: ["Only verbal communication", "Augmentative and alternative communication (AAC) ranging from simple alphabet boards to high-tech eye-gaze speech-generating devices based on current motor abilities", "Wait until the client cannot speak", "No alternatives exist"], correctIndex: 1, rationale: "ALS writing alternatives: alphabet/communication boards, voice amplification, speech-to-text software, adapted keyboards/mice, switch scanning, and eventually eye-gaze AAC systems. Introduce while the client can learn the technology.", difficulty: 2, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2391", stem: "An OTA is treating a client with a scapular winging due to long thoracic nerve injury. Which functional limitation results?", options: ["Loss of elbow flexion", "Difficulty with overhead reaching, pushing, and forward flexion because the serratus anterior cannot stabilize the scapula against the thorax", "Loss of wrist extension", "Loss of finger flexion"], correctIndex: 1, rationale: "Scapular winging (long thoracic nerve → serratus anterior): difficulty with forward flexion, overhead reaching, and pushing because scapula cannot stabilize against thorax. Compensatory strategies and scapular stabilization exercises.", difficulty: 3, category: "Anatomy & Physiology", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2392", stem: "A client with acute pancreatitis is participating in bedside OT. What symptom should the OTA monitor closely?", options: ["Only blood pressure", "Abdominal pain level, nausea, and signs of hemodynamic instability — modify activity intensity based on the client's pain and GI tolerance", "Only temperature", "Only respiratory rate"], correctIndex: 1, rationale: "Acute pancreatitis OT: monitor abdominal pain (may worsen with activity), nausea, vital signs, and activity tolerance. Grade activities to pain level, position for comfort (side-lying, knees bent), and coordinate with medical team.", difficulty: 2, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2393", stem: "An OTA is using therapeutic use of self with a client. What does this concept mean?", options: ["Physical hands-on treatment", "The therapist's deliberate and purposeful use of their personality, insights, perceptions, and interpersonal skills as part of the therapeutic process", "Using equipment only", "Self-care independence training"], correctIndex: 1, rationale: "Therapeutic use of self: the OTA consciously uses their own personality, communication style, empathy, and interpersonal skills to establish rapport, motivate clients, and facilitate therapeutic outcomes. A core skill in OT practice.", difficulty: 1, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2394", stem: "A client with a radial head fracture is 3 weeks post-injury. What motion should the OTA focus on restoring?", options: ["Shoulder rotation", "Forearm pronation and supination, as the radial head is essential for smooth forearm rotation at the proximal radioulnar joint", "Wrist flexion only", "Finger flexion only"], correctIndex: 1, rationale: "Radial head fracture: radial head pivots during pronation/supination. After healing: restore forearm rotation (pronation/supination), elbow flexion/extension, and functional activities requiring rotation (turning doorknobs, utensil use).", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2395", stem: "An OTA is providing intervention for a client with seasonal affective disorder (SAD). Which occupation-based intervention is beneficial?", options: ["Only light therapy", "Structured daily routine with outdoor activities during daylight hours, social engagement, physical activity, meaningful occupations, and use of a light therapy box during sedentary activities", "Only indoor activities", "Only evening activities"], correctIndex: 1, rationale: "SAD OT intervention: structured daily routine, outdoor activities in daylight, light therapy during activities, physical exercise, social engagement, meaningful occupations, sleep hygiene, and prevention planning for winter months.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2396", stem: "A client with a prosthetic hand has difficulty with grasp calibration. What training activity addresses this?", options: ["Only opening and closing", "Graded grasp activities with objects of varying shapes, sizes, weights, and fragility to improve proportional control and grasp force modulation", "Only heavy object grasping", "No training helps"], correctIndex: 1, rationale: "Prosthetic grasp calibration: grade objects from sturdy to fragile (cups, eggs), vary sizes/shapes/weights, practice proportional control, visual feedback training, and repetitive practice with functional objects for improved grasp force modulation.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Assistive Devices" },
  { id: "ota-2397", stem: "An OTA is providing intervention for a client with guillain-barré syndrome in the recovery phase who has foot drop. What adaptive equipment is recommended?", options: ["No equipment needed", "Ankle-foot orthosis (AFO) to maintain ankle dorsiflexion during gait and prevent tripping during functional mobility and ADLs", "Only a wheelchair", "Only crutches"], correctIndex: 1, rationale: "GBS foot drop recovery: AFO maintains ankle dorsiflexion during gait, prevents tripping, and supports functional mobility. As nerve recovery occurs, AFO may be discontinued. OT addresses the impact on ADLs and transfers.", difficulty: 2, category: "Assistive Devices", topic: "Neurological Rehab" },
  { id: "ota-2398", stem: "A client with obsessive-compulsive disorder spends 2 hours daily hand-washing. What OT approach is appropriate?", options: ["Provide unlimited handwashing time", "Exposure and response prevention: gradually reduce handwashing frequency/duration, establish time limits, and substitute with alternative coping strategies", "Increase handwashing frequency", "Only medication"], correctIndex: 1, rationale: "OCD handwashing ERP: gradual reduction of frequency/duration, time limits, alternative coping strategies (deep breathing, redirected activity), tolerate distress without washing, and structured daily routine to reduce ritual time.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2399", stem: "An OTA is evaluating a client's proprioception in the upper extremity. What test is commonly used?", options: ["Visual acuity testing", "Joint position sense testing — passively moving a joint to a position with the client's eyes closed, then asking them to replicate the position with the opposite limb", "Grip strength testing", "Two-point discrimination"], correctIndex: 1, rationale: "Proprioception testing (joint position sense): passively position a joint with client's eyes closed, ask them to replicate with opposite limb or verbally identify the position. Test distal to proximal. Impaired proprioception affects motor control.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2400", stem: "A client with end-stage Parkinson's disease is having difficulty swallowing medications. What OT recommendation addresses this?", options: ["Crush all medications", "Consult with pharmacy about medication forms (liquid, dissolvable, patches), coordinate with speech therapy for swallowing strategies, and position upright for medication administration", "Skip medications", "Only IV medications"], correctIndex: 1, rationale: "Parkinson's medication swallowing: consult pharmacy for alternative forms (not all meds can be crushed), coordinate with SLP for swallowing strategies, upright positioning, take with thickened liquids if prescribed, and timing with ON periods.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "Geriatric OT" },
  { id: "ota-2401", stem: "An OTA is treating a client with a severe hand crush injury involving multiple fractures and soft tissue damage. What is the initial treatment priority?", options: ["Grip strengthening", "Edema management, wound care, pain management, and protected gentle motion to prevent stiffness while respecting healing constraints", "Full active ROM immediately", "Discharge planning"], correctIndex: 1, rationale: "Severe crush injury initial priorities: edema management (elevation, compression), wound care, pain management, protected gentle motion (within surgeon guidelines), and splinting in functional position to prevent contractures.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2402", stem: "A client with a history of substance abuse is in an OT prevocational program. Which skill is essential to assess for work readiness?", options: ["Only physical strength", "Punctuality, following directions, frustration tolerance, social interaction, task completion, sustained attention, and ability to manage triggers in work environments", "Only academic skills", "Only manual dexterity"], correctIndex: 1, rationale: "Substance abuse prevocational assessment: punctuality, following directions, frustration tolerance, social skills, task completion, sustained attention, trigger management, stress coping, and relapse prevention strategies in work contexts.", difficulty: 2, category: "Rehabilitation Planning", topic: "ADL Training" },
];
